import azure.functions as func
import logging
import json
import os
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from datetime import datetime
import uuid

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get('STORAGE_ACCOUNT_URL', 'https://<storage-account>.blob.core.windows.net')
COSMOS_ENDPOINT = os.environ.get('COSMOS_ENDPOINT', 'https://<cosmos-account>.documents.azure.com:443/')
COSMOS_DATABASE = os.environ.get('COSMOS_DATABASE', 'mvp-database')
COSMOS_CONTAINER = os.environ.get('COSMOS_CONTAINER', 'processed-files')
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get('EVENT_GRID_TOPIC_ENDPOINT', 'https://<topic-name>.<region>.eventgrid.azure.net/api/events')

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_TOPIC_ENDPOINT, credential)

# Get Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE)
container = database.get_container_client(COSMOS_CONTAINER)


@app.blob_trigger(arg_name="myblob", path="input-files/{name}",
                  connection="STORAGE_ACCOUNT_URL")
def process_blob_file(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read blob content
        blob_content = myblob.read()
        
        # Process the file (example: count lines for text files, calculate size for others)
        processing_result = process_file_content(blob_content, myblob.name)
        
        # Create document for Cosmos DB
        document = {
            "id": str(uuid.uuid4()),
            "fileName": myblob.name,
            "blobUrl": f"{STORAGE_ACCOUNT_URL}/{myblob.name}",
            "fileSize": myblob.length,
            "processedAt": datetime.utcnow().isoformat(),
            "processingResult": processing_result,
            "status": "completed"
        }
        
        # Write to Cosmos DB
        container.create_item(body=document)
        logging.info(f"Document written to Cosmos DB: {document['id']}")
        
        # Send notification via Event Grid
        event = CloudEvent(
            type="FileProcessing.Completed",
            source=f"/blobstorage/{myblob.name}",
            data={
                "documentId": document["id"],
                "fileName": myblob.name,
                "fileSize": myblob.length,
                "status": "completed",
                "processedAt": document["processedAt"],
                "result": processing_result
            }
        )
        
        event_grid_client.send([event])
        logging.info(f"Event sent to Event Grid for file: {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        
        # Log error to Cosmos DB
        error_document = {
            "id": str(uuid.uuid4()),
            "fileName": myblob.name,
            "blobUrl": f"{STORAGE_ACCOUNT_URL}/{myblob.name}",
            "processedAt": datetime.utcnow().isoformat(),
            "status": "failed",
            "error": str(e)
        }
        
        try:
            container.create_item(body=error_document)
            
            # Send error notification
            error_event = CloudEvent(
                type="FileProcessing.Failed",
                source=f"/blobstorage/{myblob.name}",
                data={
                    "documentId": error_document["id"],
                    "fileName": myblob.name,
                    "status": "failed",
                    "error": str(e),
                    "processedAt": error_document["processedAt"]
                }
            )
            event_grid_client.send([error_event])
        except Exception as nested_error:
            logging.error(f"Failed to log error: {str(nested_error)}")
        
        raise


def process_file_content(content: bytes, filename: str) -> dict:
    """Process file content and return results"""
    result = {
        "contentSize": len(content),
        "fileType": get_file_type(filename)
    }
    
    # Try to process as text
    try:
        text_content = content.decode('utf-8')
        result["lineCount"] = len(text_content.splitlines())
        result["characterCount"] = len(text_content)
        result["wordCount"] = len(text_content.split())
    except UnicodeDecodeError:
        result["lineCount"] = None
        result["characterCount"] = None
        result["wordCount"] = None
        result["note"] = "Binary file, text analysis not available"
    
    return result


def get_file_type(filename: str) -> str:
    """Extract file extension"""
    if '.' in filename:
        return filename.rsplit('.', 1)[1].lower()
    return "unknown"


@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Health check endpoint called')
    
    health_status = {
        "status": "healthy",
        "timestamp": datetime.utcnow().isoformat(),
        "services": {}
    }
    
    # Check Blob Storage connectivity
    try:
        list(blob_service_client.list_containers(max_results=1))
        health_status["services"]["blobStorage"] = "connected"
    except Exception as e:
        health_status["services"]["blobStorage"] = f"error: {str(e)}"
        health_status["status"] = "degraded"
    
    # Check Cosmos DB connectivity
    try:
        database.read()
        health_status["services"]["cosmosDb"] = "connected"
    except Exception as e:
        health_status["services"]["cosmosDb"] = f"error: {str(e)}"
        health_status["status"] = "degraded"
    
    # Event Grid doesn't have a simple health check, so we just note it's configured
    health_status["services"]["eventGrid"] = "configured"
    
    return func.HttpResponse(
        json.dumps(health_status, indent=2),
        mimetype="application/json",
        status_code=200 if health_status["status"] == "healthy" else 503
    )


@app.route(route="query", methods=["GET"])
def query_processed_files(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Query endpoint called')
    
    try:
        # Get query parameters
        status = req.params.get('status')
        limit = int(req.params.get('limit', 100))
        
        # Build query
        if status:
            query = f"SELECT * FROM c WHERE c.status = @status ORDER BY c.processedAt DESC OFFSET 0 LIMIT @limit"
            parameters = [
                {"name": "@status", "value": status},
                {"name": "@limit", "value": limit}
            ]
        else:
            query = f"SELECT * FROM c ORDER BY c.processedAt DESC OFFSET 0 LIMIT @limit"
            parameters = [{"name": "@limit", "value": limit}]
        
        # Execute query
        items = list(container.query_items(
            query=query,
            parameters=parameters,
            enable_cross_partition_query=True
        ))
        
        return func.HttpResponse(
            json.dumps({"count": len(items), "items": items}, indent=2),
            mimetype="application/json",
            status_code=200
        )
    
    except Exception as e:
        logging.error(f"Error querying files: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )


@app.route(route="reprocess/{file_id}", methods=["POST"])
def reprocess_file(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Reprocess endpoint called')
    
    try:
        file_id = req.route_params.get('file_id')
        
        # Get document from Cosmos DB
        document = container.read_item(item=file_id, partition_key=file_id)
        
        # Extract blob path from URL
        blob_name = document.get('fileName')
        
        # Trigger reprocessing by copying blob to trigger location
        container_name = blob_name.split('/')[0] if '/' in blob_name else 'input-files'
        source_blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        # Create a copy operation (this would trigger the blob trigger again)
        target_blob_client = blob_service_client.get_blob_client(
            container='input-files',
            blob=f"reprocess/{datetime.utcnow().isoformat()}/{blob_name.split('/')[-1]}"
        )
        
        target_blob_client.start_copy_from_url(source_blob_client.url)
        
        return func.HttpResponse(
            json.dumps({
                "message": "Reprocessing initiated",
                "fileId": file_id,
                "fileName": blob_name
            }),
            mimetype="application/json",
            status_code=202
        )
    
    except Exception as e:
        logging.error(f"Error reprocessing file: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )